const question = $.input.question;
const context = $.input.conversationContext || '';
let query = question;
if (context) query = question + ' context: ' + context.slice(0, 200);
return { query };

const results = $.steps.webResearch.response.results || [];
let sources = '';
results.forEach((r, i) => {
  sources += '[' + (i + 1) + '] ' + (r.title || 'Untitled') + '\n';
  sources += '    URL: ' + (r.url || '') + '\n';
  sources += '    ' + (r.text || '').slice(0, 1200) + '\n\n';
});
return { sources, sourceCount: results.length, sourceList: results.map((r, i) => ({ num: i + 1, title: r.title || '', url: r.url || '' })) };

const d = $.steps.compileSources.output;
const question = $.input.question;
const context = $.input.conversationContext || '';
const style = $.input.responseStyle || 'conversational';
const language = $.input.language || 'English';

let prompt = 'You are a knowledgeable conversational AI assistant. Answer the user\'s question using the research sources provided.\n\n';
prompt += 'QUESTION: ' + question + '\n';
if (context) prompt += 'CONVERSATION CONTEXT: ' + context + '\n';
prompt += 'RESPONSE STYLE: ' + style + '\n';
prompt += 'LANGUAGE: ' + language + '\n\n';
prompt += 'RESEARCH SOURCES (' + d.sourceCount + '):\n';
prompt += d.sources + '\n\n';
prompt += 'INSTRUCTIONS:\n';
prompt += '- Answer in a ' + style + ' tone\n';
prompt += '- Cite sources using [N] notation\n';
prompt += '- If the question is ambiguous, address the most likely interpretation\n';
prompt += '- Include relevant examples or analogies\n';
prompt += '- Suggest follow-up questions the user might want to ask\n';
prompt += '- Use Slack mrkdwn: *bold* (NOT **bold**), _italic_, numbered lists\n';
prompt += '- Respond in ' + language + '\n\n';
prompt += 'Return ONLY valid JSON:\n';
prompt += '{\n';
prompt += '  "answer": "the complete answer in Slack mrkdwn with [N] citations",\n';
prompt += '  "confidence": "high|medium|low",\n';
prompt += '  "topic": "inferred topic category",\n';
prompt += '  "keyPoints": ["main takeaway 1", "main takeaway 2"],\n';
prompt += '  "followUpQuestions": ["suggested follow-up 1", "suggested follow-up 2"],\n';
prompt += '  "sourcesUsed": [1, 3, 5]\n';
prompt += '}';

return { prompt };

let raw = $.steps.aiAnswer.output || '';
raw = raw.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/\s*```$/i, '').trim();
try { return JSON.parse(raw); } catch(e) { return { answer: raw, confidence: 'medium', topic: '', keyPoints: [], followUpQuestions: [], sourcesUsed: [] }; }

const ai = $.steps.parseAI.output;
const sources = $.steps.compileSources.output.sourceList || [];
const confidenceEmoji = ai.confidence === 'high' ? ':large_green_circle:' : ai.confidence === 'low' ? ':red_circle:' : ':large_yellow_circle:';

const blocks = [];
blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*Q:* ' + $.input.question } });
blocks.push({ type: 'divider' });

const answer = (ai.answer || 'No answer generated.').slice(0, 2900);
blocks.push({ type: 'section', text: { type: 'mrkdwn', text: answer } });
blocks.push({ type: 'divider' });

if (ai.keyPoints && ai.keyPoints.length > 0) {
  let kpText = '*Key Points:*\n';
  ai.keyPoints.forEach((p, i) => { kpText += (i + 1) + '. ' + p + '\n'; });
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: kpText.slice(0, 1800) } });
}

const usedSources = (ai.sourcesUsed || []).map(n => sources.find(s => s.num === n)).filter(Boolean);
if (usedSources.length > 0) {
  let srcText = '*Sources:*\n';
  usedSources.forEach(s => { srcText += '[' + s.num + '] <' + s.url + '|' + s.title + '>\n'; });
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: srcText.slice(0, 1800) } });
}

if (ai.followUpQuestions && ai.followUpQuestions.length > 0) {
  let fqText = '*You might also ask:*\n';
  ai.followUpQuestions.forEach((q, i) => { fqText += '  ' + (i + 1) + '. ' + q + '\n'; });
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: fqText.slice(0, 800) } });
}

blocks.push({ type: 'context', elements: [{ type: 'mrkdwn', text: confidenceEmoji + ' ' + (ai.topic || '') + ' | Powered by Exa + Claude AI' }] });
const fallback = 'Answer: ' + (ai.answer || '').slice(0, 100);
return { blocks, fallback };
